class Maps{constructor(){const $=selector=>document.querySelector(selector);const $$=selector=>document.querySelectorAll(selector);this.WAIT_TIME_MS=500;this.BUTTONS_MAP={get zoomIn(){return $("#zoomInButton")},get menu(){return $("#map-action-menu")},get imprimir_mapa(){return $$("#mapmenu-print")[$$("#mapmenu-print").length-1]},get paisagem(){return $("#print-dialog-landscape span:last-child")},get imagem(){return $("#print-dialog-output-image span:last-child")},get a5(){return $(".VIpgJd-xl07Ob.VIpgJd-xl07Ob-GP8zAc:last-child > div:nth-child(7)")},get imprimir(){return $('button[name="print"]')},get zoomOut(){return $("#zoomOutButton")}};this.BUTTONS_IMPORT={get menuLayer(){return $(".un1lmc-j4gsHd")},get menuReimportarMesclar(){return $$(".VIpgJd-j7LFlb.VIpgJd-eKm5Fc")[0]},get menuReimportar(){return $$(".VIpgJd-j7LFlb.VIpgJd-eKm5Fc .VIpgJd-j7LFlb-bN97Pc")[$$(".VIpgJd-j7LFlb.VIpgJd-eKm5Fc .VIpgJd-j7LFlb-bN97Pc").length-1]},get menuSubstituir(){return $(".VIpgJd-xl07Ob.VIpgJd-xl07Ob-BvBYQ:last-child > div:first-child")}};this.LAYERS={get all(){return document.getElementsByClassName("pbTTYe")},get icones_div(){return $$(".un1lmc-pbTTYe-ibnC6b-BwqjC")},get icones_image(){return $$(".pbTTYe img")},get enderecos(){return $$(".un1lmc-pbTTYe-ibnC6b-r4nke")}};if($$("#print").length>0){$("body").classList.add("print")}}async wait(ms){const milliseconds=ms||this.WAIT_TIME_MS;return new Promise(resolve=>setTimeout(resolve,milliseconds))}getElement(selector){if(typeof selector==="string"){return document.querySelector(selector)}else if(selector instanceof HTMLElement){return selector}return null}simulateClick(element){const $element=this.getElement(element);const mouseDown=new MouseEvent("mousedown",{bubbles:true,cancelable:true,view:window});const mouseUp=new MouseEvent("mouseup",{bubbles:true,cancelable:true,view:window});const click=new MouseEvent("click",{bubbles:true,cancelable:true,view:window});$element.dispatchEvent(mouseDown);$element.dispatchEvent(mouseUp);$element.dispatchEvent(click)}typeAndEnter(element,value){const $input=this.getElement(element);if(!$input){console.error("Input não encontrado para selector:",element);return false}$input.focus();const nativeInputSetter=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,"value").set;nativeInputSetter.call($input,value);$input.dispatchEvent(new Event("input",{bubbles:true}));$input.dispatchEvent(new Event("change",{bubbles:true}));$input.dispatchEvent(new KeyboardEvent("keydown",{key:"Enter",keyCode:13,bubbles:true}));$input.dispatchEvent(new KeyboardEvent("keypress",{key:"Enter",keyCode:13,bubbles:true}));$input.dispatchEvent(new KeyboardEvent("keyup",{key:"Enter",keyCode:13,bubbles:true}));return true}getIconsMap(){const icones=[];for(const icone of Array.from(this.LAYERS["icones_div"])){if(icone.getAttribute("iconcode")!="1739-000000"){icones.push(icone.style.backgroundImage.split('"')[1])}}return icones}setIcons(){const icones=JSON.stringify(this.getIconsMap());localStorage.setItem("icones",icones)}getIcons(){const icones=JSON.parse(localStorage.getItem("icones"));return icones}replaceIcons(){const icones=this.getIcons();if(icones.length>0){this.LAYERS["icones_image"].forEach(function(imagem,index){imagem.src=icones[index]})}}removeFirstLayer(){for(const layer of this.LAYERS["all"]){if(layer.innerText.includes("Todos os itens")){layer.remove()}}}addEventReplaceBr(){this.LAYERS["enderecos"].forEach(function(div){div.addEventListener("dblclick",function(){if(div.innerHTML.includes("<br>")){div.innerHTML=div.innerHTML.replace(/<br>/g,"")}else{div.innerHTML=div.innerHTML.replace(/#/g,"<br>#")}})})}checkIfExtensionLoaded(){if(typeof window.mapsAutomation=="object"){return true}else{return false}}static frame(){const $molduras=document.querySelectorAll(".moldura");if($molduras.length<1){const elementos=["t","r","b","l"];for(const elemento of elementos){const div=document.createElement("div");div.classList.add("moldura",elemento);document.body.appendChild(div)}}else if($molduras[0].style.display=="none"){$molduras.forEach(function($moldura){$moldura.style.display="block"})}else{$molduras.forEach(function($moldura){$moldura.style.display="none"})}}async importFile(){this.setIcons();for(const button in this.BUTTONS_IMPORT){this.simulateClick(this.BUTTONS_IMPORT[button]);await this.wait()}}async loadFile(){if(!this.checkIfExtensionLoaded()){console.error("A extensão não foi detectada.");return}await mapsAutomation.clickNoPicker('button[id="1"]');await mapsAutomation.typeAndEnter("Direcciones");await this.wait(2e3);await mapsAutomation.clickFirstResult('[data-id="1T5YaD-KZgqogJBSBNOOsT9-cP5pK2ROYORvTYwfAA-Q"]')}async importAndLoadFile(){await this.importFile();await this.wait(1e3);await this.loadFile()}async generateMAP(){this.setIcons();for(const button in this.BUTTONS_MAP){this.simulateClick(this.BUTTONS_MAP[button]);await this.wait()}}generatePDF(){this.removeFirstLayer();this.replaceIcons();this.addEventReplaceBr()}}